// // This module implements a 4-to-1 multiplexer with two selection lines (sel0 and sel1) and two data inputs (in0 and in1). The output, dout, is determined based on the values of the selection lines: when both sel lines are LOW (00), dout outputs a HIGH state; when sel0 is HIGH (01), it outputs the value of in1; when sel1 is HIGH (10), it outputs the value of in0; and when both sel lines are HIGH (11), dout is set to a known state (0).
module top_module(dout, in0, in1, sel0, sel1);output dout;
  input in0, in1, sel0, sel1;

  reg dout;

  always @ (sel1 or sel0 or in0 or in1) begin
    case ({sel1, sel0})
      2'b00: dout = 1'b0;
      2'b01: dout = in0;
      2'b10: dout = in1;
      2'b11: dout = 1'bx;
    endcase
  end

endmodule
